package com.composerUI.library.components

import androidx.compose.animation.animateContentSize
import androidx.compose.animation.core.animateFloatAsState
import androidx.compose.animation.core.tween
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.KeyboardArrowDown
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.draw.rotate
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.dp

@Composable
fun PremiumAccordion(
    title: String,
    modifier: Modifier = Modifier,
    expanded: Boolean = false,
    onExpandChange: (Boolean) -> Unit = {},
    cornerRadius: Dp = {$CornerRadius_01}.dp,
    containerColor: Color = Color(android.graphics.Color.parseColor("{$ContainerColor_01}")),
    content: @Composable () -> Unit
) {
    val rotationState by animateFloatAsState(
        targetValue = if (expanded) 180f else 0f,
        label = "rotation"
    )

    Surface(
        modifier = modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(cornerRadius))
            .clickable { onExpandChange(!expanded) }
            .animateContentSize(
                animationSpec = tween(durationMillis = 300)
            ),
        color = containerColor,
        shape = RoundedCornerShape(cornerRadius),
        border = AssistChipDefaults.assistChipBorder(enabled = true, borderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.2f))
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Text(
                    text = title,
                    style = MaterialTheme.typography.titleMedium,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
                Icon(
                    imageVector = Icons.Default.KeyboardArrowDown,
                    contentDescription = if (expanded) "Collapse" else "Expand",
                    modifier = Modifier.rotate(rotationState),
                    tint = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }

            if (expanded) {
                Spacer(modifier = Modifier.height(12.dp))
                Box(modifier = Modifier.fillMaxWidth()) {
                    content()
                }
            }
        }
    }
}

//[FILENAME:AnimatedStepIndicator.kt]

package com.composerUI.library.components.complex

import androidx.compose.animation.animateColorAsState
import androidx.compose.animation.core.animateFloatAsState
import androidx.compose.animation.core.tween
import androidx.compose.foundation.background
import androidx.compose.foundation.border
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Check
import androidx.compose.material3.Icon
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp

enum class StepperOrientation { Horizontal, Vertical }

@Composable
fun AnimatedStepIndicator(
    currentStep: Int = {$CurrentStep_01},
    totalSteps: Int = {$TotalSteps_01},
    modifier: Modifier = Modifier,
    stepLabels: List<String> = listOf("{$Label1_01}", "{$Label2_01}", "{$Label3_01}", "{$Label4_01}", "{$Label5_01}"),
    orientation: StepperOrientation = StepperOrientation.valueOf("{$Orientation_01}"),
    activeColor: Color = Color(android.graphics.Color.parseColor("{$ActiveColor_01}")),
    inactiveColor: Color = Color(android.graphics.Color.parseColor("{$InactiveColor_01}")),
    completedColor: Color = Color(android.graphics.Color.parseColor("{$CompletedColor_01}"))
) {
    if (orientation == StepperOrientation.Horizontal) {
        Row(
            modifier = modifier.fillMaxWidth(),
            verticalAlignment = Alignment.CenterVertically
        ) {
            for (i in 0 until totalSteps) {
                StepItem(
                    index = i,
                    currentStep = currentStep,
                    totalSteps = totalSteps,
                    label = stepLabels.getOrNull(i),
                    orientation = orientation,
                    activeColor = activeColor,
                    inactiveColor = inactiveColor,
                    completedColor = completedColor,
                    modifier = Modifier.weight(1f, fill = i != totalSteps - 1)
                )
            }
        }
    } else {
        Column(
            modifier = modifier.fillMaxHeight(),
            horizontalAlignment = Alignment.Start
        ) {
            for (i in 0 until totalSteps) {
                StepItem(
                    index = i,
                    currentStep = currentStep,
                    totalSteps = totalSteps,
                    label = stepLabels.getOrNull(i),
                    orientation = orientation,
                    activeColor = activeColor,
                    inactiveColor = inactiveColor,
                    completedColor = completedColor
                )
            }
        }
    }
}

@Composable
private fun StepItem(
    index: Int,
    currentStep: Int,
    totalSteps: Int,
    label: String?,
    orientation: StepperOrientation,
    activeColor: Color,
    inactiveColor: Color,
    completedColor: Color,
    modifier: Modifier = Modifier
) {
    val isCompleted = index < currentStep
    val isActive = index == currentStep

    val circleColor by animateColorAsState(
        targetValue = when {
            isCompleted -> completedColor
            isActive -> activeColor
            else -> inactiveColor
        },
        label = "circleColor"
    )

    if (orientation == StepperOrientation.Horizontal) {
        Row(
            verticalAlignment = Alignment.CenterVertically,
            modifier = modifier
        ) {
            StepCircle(circleColor, index + 1, isCompleted)

            if (index < totalSteps - 1) {
                val progress by animateFloatAsState(
                    targetValue = if (index < currentStep) 1f else 0f,
                    animationSpec = tween(500),
                    label = "lineProgress"
                )

                Box(
                    modifier = Modifier
                        .weight(1f)
                        .height(4.dp)
                        .padding(horizontal = 4.dp)
                        .background(inactiveColor, CircleShape)
                ) {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth(progress)
                            .fillMaxHeight()
                            .background(if (index < currentStep) completedColor else activeColor, CircleShape)
                    )
                }
            }
        }
    } else {
        Row(modifier = Modifier.padding(bottom = 8.dp)) {
            Column(
                horizontalAlignment = Alignment.CenterHorizontally,
                modifier = Modifier.width(32.dp)
            ) {
                StepCircle(circleColor, index + 1, isCompleted)

                if (index < totalSteps - 1) {
                    val progress by animateFloatAsState(
                        targetValue = if (index < currentStep) 1f else 0f,
                        animationSpec = tween(500),
                        label = "lineProgressVertical"
                    )
                    Box(
                        modifier = Modifier
                            .width(4.dp)
                            .height(40.dp)
                            .padding(vertical = 4.dp)
                            .background(inactiveColor, CircleShape)
                    ) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .fillMaxHeight(progress)
                                .background(if (index < currentStep) completedColor else activeColor, CircleShape)
                        )
                    }
                }
            }

            if (label != null) {
                Column(modifier = Modifier.padding(start = 12.dp, top = 4.dp)) {
                    Text(
                        text = label,
                        style = MaterialTheme.typography.bodyLarge,
                        fontWeight = if (isActive) FontWeight.Bold else FontWeight.Medium,
                        color = if (isActive) activeColor else MaterialTheme.colorScheme.onSurface
                    )
                }
            }
        }
    }
}

@Composable
private fun StepCircle(color: Color, stepNumber: Int, isCompleted: Boolean) {
    Box(
        modifier = Modifier
            .size(32.dp)
            .clip(CircleShape)
            .background(color)
            .border(2.dp, color.copy(alpha = 0.5f), CircleShape),
        contentAlignment = Alignment.Center
    ) {
        if (isCompleted) {
            Icon(
                imageVector = Icons.Default.Check,
                contentDescription = null,
                tint = Color.White,
                modifier = Modifier.size(20.dp)
            )
        } else {
            Text(
                text = stepNumber.toString(),
                color = Color.White,
                style = MaterialTheme.typography.labelLarge,
                fontWeight = FontWeight.Bold
            )
        }
    }
}
